@typeparam TItem

@if (_items is { Count: > 0 })
{
    <ul>
        @for (var i = 0; i < _items.Count; i++)
        {
            var index = i;
            <li @key="_items[index]">
                @ItemTemplate(_items[index])
                <button @onclick="() => MoveUp(index)" disabled="@(index == 0)">Move Up</button>
                <button @onclick="() => MoveDown(index)" disabled="@(index == _items.Count - 1)">Move Down</button>
            </li>
        }
    </ul>
}

using Microsoft.AspNetCore.Components;

public partial class SortableList<TItem>
{
    private List<TItem> _items = new();

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = default!;

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ItemTemplate { get; set; } = default!;

    [Parameter]
    public EventCallback<IReadOnlyList<TItem>> OnOrderChanged { get; set; }

    protected override void OnParametersSet()
    {
        _items = new List<TItem>(Items);
    }

    private async Task MoveUp(int index)
    {
        if (index <= 0) return;

        (_items[index - 1], _items[index]) = (_items[index], _items[index - 1]);
        await OnOrderChanged.InvokeAsync(_items.AsReadOnly());
    }

    private async Task MoveDown(int index)
    {
        if (index >= _items.Count - 1) return;

        (_items[index], _items[index + 1]) = (_items[index + 1], _items[index]);
        await OnOrderChanged.InvokeAsync(_items.AsReadOnly());
    }
}

